class MagixUITools{constructor(s){this.sidebarId=s.sidebarId||"aside",this.toggleId=s.toggleId||"sidebarToggle",this.backdropId=s.backdropId||"sidebar-backdrop",this.toggledClass="is-toggled",this.showClass="show",this.sidebar=document.getElementById(this.sidebarId),this.toggleBtn=document.getElementById(this.toggleId),this.backdrop=document.getElementById(this.backdropId),this.breakpoint=992}init(){this.sidebar&&(this.handleToggle(),this.handleBackdrop(),this.handleResize(),this.handleAutoExpand(),this.scrollToActiveItem())}handleToggle(){this.toggleBtn&&this.toggleBtn.addEventListener("click",(()=>{this.sidebar.classList.toggle(this.toggledClass),window.innerWidth<this.breakpoint&&this.backdrop&&this.backdrop.classList.toggle(this.showClass)}))}handleBackdrop(){this.backdrop&&this.backdrop.addEventListener("click",(()=>{this.sidebar.classList.remove(this.toggledClass),this.backdrop.classList.remove(this.showClass)}))}handleResize(){window.addEventListener("resize",(()=>{window.innerWidth>=this.breakpoint&&this.backdrop&&this.backdrop.classList.remove(this.showClass)}))}handleAutoExpand(){this.sidebar.addEventListener("click",(s=>{if(window.innerWidth>=this.breakpoint&&this.sidebar.classList.contains(this.toggledClass)){s.target.closest(".btn-toggle, .nav-link")&&this.sidebar.classList.remove(this.toggledClass)}}))}scrollToActiveItem(){const s=this.sidebar.querySelector(".active-sub")||this.sidebar.querySelector(".nav-link.active");s&&setTimeout((()=>{s.scrollIntoView({behavior:"auto",block:"center"})}),50)}}